import json
import boto3
from typing import Dict, Any

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    Sample Lambda function that demonstrates shared IAM role usage
    """
    try:
        # Initialize clients with implicit credentials from shared role
        s3_client = boto3.client('s3')
        dynamodb_client = boto3.client('dynamodb')
        sns_client = boto3.client('sns')
        sqs_client = boto3.client('sqs')
        
        # Example operations using shared permissions
        # S3 operations
        buckets = s3_client.list_buckets()
        
        # DynamoDB operations
        tables = dynamodb_client.list_tables()
        
        # SNS operations
        topics = sns_client.list_topics()
        
        # SQS operations
        queues = sqs_client.list_queues()
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Successfully accessed AWS services',
                's3_buckets': len(buckets.get('Buckets', [])),
                'dynamodb_tables': len(tables.get('TableNames', [])),
                'sns_topics': len(topics.get('Topics', [])),
                'sqs_queues': len(queues.get('QueueUrls', []))
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': str(e)
            })
        }

